import { useState } from 'react';

export function Counter() {
  const [n, setN] = useState(0);
  return <button onClick={() => setN(n + 1)}>{n}</button>;
}

import { useEffect, useState } from 'react';

export function Title() {
  const [t, setT] = useState('');
  useEffect(() => { document.title = t || 'App'; }, [t]);
  return <input value={t} onChange={(e) => setT(e.target.value)} />;
}

function Hello({ who }: { who: string }) {
  return <p>Hello, {who.toUpperCase()}</p>;
}

type Props = { label: string };

export function PrimaryButton({ label }: Props) {
  return <button className="primary" type="button">{label}</button>;
}

export function Box({ x }: { x: number }) {
  return <div style={{ width: x }} />;
}

import { memo, useState } from 'react';

const Row = memo(function Row({ text }: { text: string }) {
  return <li>{text}</li>;
});

export function List() {
  const [items] = useState(['a', 'b']);
  return <ul>{items.map((t) => <Row key={t} text={t} />)}</ul>;
}

import { useState } from 'react';

export function Form() {
  const [email, setEmail] = useState('');
  return <input value={email} onChange={(e) => setEmail(e.target.value)} />;
}

function Greet({ name }: { name: string }) {
  return <h1>Hello, {name}</h1>;
}

export function App() {
  return <Greet name="Asha" />;
}
